<template>  <div class="dashboard">    <div class="stats-cards">      <el-row :gutter="20">        <el-col :span="6">          <el-card class="stats-card">            <div class="stats-content">              <div class="stats-icon">                <el-icon size="32" color="#409EFF"><User /></el-icon>              </div>              <div class="stats-info">                <div class="stats-number">{{ stats.totalUsers }}</div>                <div class="stats-label">总用户数</div>              </div>            </div>          </el-card>        </el-col>        <el-col :span="6">          <el-card class="stats-card">            <div class="stats-content">              <div class="stats-icon">                <el-icon size="32" color="#67C23A"><UserFilled /></el-icon>              </div>              <div class="stats-info">                <div class="stats-number">{{ stats.activeUsers }}</div>                <div class="stats-label">活跃用户</div>              </div>            </div>          </el-card>        </el-col>        <el-col :span="6">          <el-card class="stats-card">            <div class="stats-content">              <div class="stats-icon">                <el-icon size="32" color="#E6A23C"><Star /></el-icon>              </div>              <div class="stats-info">                <div class="stats-number">{{ stats.totalRoles }}</div>                <div class="stats-label">角色数量</div>              </div>            </div>          </el-card>        </el-col>        <el-col :span="6">          <el-card class="stats-card">            <div class="stats-content">              <div class="stats-icon">                <el-icon size="32" color="#F56C6C"><Menu /></el-icon>              </div>              <div class="stats-info">                <div class="stats-number">{{ stats.totalMenus }}</div>                <div class="stats-label">菜单数量</div>              </div>            </div>          </el-card>        </el-col>      </el-row>    </div>    <div class="charts-section">      <el-row :gutter="20">        <el-col :span="12">          <el-card>            <template #header>              <div class="card-header">                <span>用户状态分布</span>              </div>            </template>            <div class="chart-container">              <el-progress                type="circle"                :percentage="userStatusChart.active"                color="#67C23A"                :stroke-width="8"                class="chart-item"              >                <template #default>                  <div class="chart-label">                    <div class="chart-number">{{ stats.activeUsers }}</div>                    <div class="chart-text">活跃用户</div>                  </div>                </template>              </el-progress>              <el-progress                type="circle"                :percentage="userStatusChart.inactive"                color="#F56C6C"                :stroke-width="8"                class="chart-item"              >                <template #default>                  <div class="chart-label">                    <div class="chart-number">{{ stats.totalUsers - stats.activeUsers }}</div>                    <div class="chart-text">禁用用户</div>                  </div>                </template>              </el-progress>            </div>          </el-card>        </el-col>        <el-col :span="12">          <el-card>            <template #header>              <div class="card-header">                <span>系统信息</span>              </div>            </template>            <div class="system-info">              <div class="info-item">                <span class="info-label">系统版本:</span>                <span class="info-value">RBAC v1.0.0</span>              </div>              <div class="info-item">                <span class="info-label">前端框架:</span>                <span class="info-value">Vue 3 + Element Plus</span>              </div>              <div class="info-item">                <span class="info-label">后端框架:</span>                <span class="info-value">Node.js + Express</span>              </div>              <div class="info-item">                <span class="info-label">数据库:</span>                <span class="info-value">MySQL + Prisma</span>              </div>              <div class="info-item">                <span class="info-label">当前用户:</span>                <span class="info-value">{{ authStore.user?.username }}</span>              </div>              <div class="info-item">                <span class="info-label">登录时间:</span>                <span class="info-value">{{ formatDate(new Date()) }}</span>              </div>            </div>          </el-card>        </el-col>      </el-row>    </div>    <div class="recent-activity">      <el-card>        <template #header>          <div class="card-header">            <span>最近活动</span>          </div>        </template>        <el-timeline>          <el-timeline-item            v-for="activity in recentActivities"            :key="activity.id"            :timestamp="formatDate(activity.timestamp)"          >            <div class="activity-content">              <el-icon class="activity-icon">                <component :is="activity.icon" />              </el-icon>              <span>{{ activity.description }}</span>            </div>          </el-timeline-item>        </el-timeline>      </el-card>    </div>  </div></template><script>import { ref, reactive, onMounted } from 'vue'import { useAuthStore } from '../stores/auth'import axios from 'axios'import { User, UserFilled, Star, Menu } from '@element-plus/icons-vue'export default {  name: 'DashboardView',  components: {    User,    UserFilled,    Star,    Menu  },  setup() {    const authStore = useAuthStore()    const stats = reactive({      totalUsers: 0,      activeUsers: 0,      totalRoles: 0,      totalMenus: 0    })    const userStatusChart = reactive({      active: 0,      inactive: 0    })    const recentActivities = ref([      {        id: 1,        description: '用户登录系统',        timestamp: new Date(),        icon: 'User'      },      {        id: 2,        description: '查看用户管理页面',        timestamp: new Date(Date.now() - 1000 * 60 * 5),        icon: 'UserFilled'      },      {        id: 3,        description: '更新角色权限',        timestamp: new Date(Date.now() - 1000 * 60 * 15),        icon: 'Star'      }    ])    const fetchStats = async () => {      try {        const [usersRes, rolesRes, menusRes] = await Promise.all([          axios.get('http://localhost:3000/api/users', {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          }),          axios.get('http://localhost:3000/api/roles', {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          }),          axios.get('http://localhost:3000/api/menus', {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })        ])        if (usersRes.data.success) {          const users = usersRes.data.data          stats.totalUsers = users.length          stats.activeUsers = users.filter(u => u.status === 'active').length          userStatusChart.active = stats.totalUsers > 0 ? Math.round((stats.activeUsers / stats.totalUsers) * 100) : 0          userStatusChart.inactive = 100 - userStatusChart.active        }        if (rolesRes.data.success) {          stats.totalRoles = rolesRes.data.data.length        }        if (menusRes.data.success) {          stats.totalMenus = menusRes.data.data.length        }      } catch (error) {        console.error('Fetch stats error:', error)      }    }    const formatDate = (date) => {      return new Intl.DateTimeFormat('zh-CN', {        year: 'numeric',        month: '2-digit',        day: '2-digit',        hour: '2-digit',        minute: '2-digit'      }).format(date)    }    onMounted(() => {      fetchStats()    })    return {      authStore,      stats,      userStatusChart,      recentActivities,      formatDate    }  }}</script><style scoped>.dashboard {  padding: 20px;}.stats-cards {  margin-bottom: 20px;}.stats-card {  height: 120px;}.stats-content {  display: flex;  align-items: center;  height: 100%;}.stats-icon {  margin-right: 20px;}.stats-info {  flex: 1;}.stats-number {  font-size: 32px;  font-weight: bold;  color: #303133;  line-height: 1;}.stats-label {  font-size: 14px;  color: #909399;  margin-top: 8px;}.charts-section {  margin-bottom: 20px;}.chart-container {  display: flex;  justify-content: space-around;  align-items: center;}.chart-item {  width: 120px;}.chart-label {  text-align: center;}.chart-number {  font-size: 24px;  font-weight: bold;  color: #303133;}.chart-text {  font-size: 12px;  color: #909399;  margin-top: 4px;}.system-info {  display: flex;  flex-direction: column;  gap: 12px;}.info-item {  display: flex;  justify-content: space-between;  align-items: center;}.info-label {  font-weight: 500;  color: #606266;}.info-value {  color: #303133;}.recent-activity {  margin-bottom: 20px;}.activity-content {  display: flex;  align-items: center;}.activity-icon {  margin-right: 8px;}.card-header {  display: flex;  justify-content: space-between;  align-items: center;}</style>